import React, { useState, useEffect } from "react";

function ProductForm({ productToEdit, onSaveComplete }) {

  // Estados del formulario
  const [name, setName] = useState("");
  const [descripcion, setDescripcion] = useState("");
  const [categoria, setCategoria] = useState("");
  const [precio, setPrecio] = useState("");

  // Cuando cambia el producto a editar
  useEffect(() => {
    if (productToEdit) {
      setName(productToEdit.name);
      setDescripcion(productToEdit.descripcion);
      setCategoria(productToEdit.categoria);
      setPrecio(productToEdit.precio);
    } else {
      setName("");
      setDescripcion("");
      setCategoria("");
      setPrecio("");
    }
  }, [productToEdit]);

  // Enviar formulario
  const handleSubmit = (e) => {
    e.preventDefault();

    const newProduct = {
      name,
      descripcion,
      categoria,
      precio
    };

    const method = productToEdit ? "PUT" : "POST";

    const url = productToEdit
      ? `http://localhost:3000/api/products/${productToEdit._id}`
      : "http://localhost:3000/api/products";

    fetch(url, {
      method,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(newProduct)
    })
      .then(res => res.json())
      .then(data => {

        const nombreMostrar = data.name || name;

        alert(
          productToEdit
            ? `Producto ${nombreMostrar} actualizado`
            : `Producto ${nombreMostrar} creado`
        );

        // limpiar formulario
        setName("");
        setDescripcion("");
        setCategoria("");
        setPrecio("");

        onSaveComplete();

      })
      .catch(err => console.error("Error:", err));
  };

  return (
    <form onSubmit={handleSubmit}>

      <h2>{productToEdit ? "Editar Producto" : "Agregar Producto"}</h2>

      <input
        type="text"
        placeholder="Nombre"
        value={name}
        onChange={(e) => setName(e.target.value)}
        required
      />

      <input
        type="text"
        placeholder="Descripción"
        value={descripcion}
        onChange={(e) => setDescripcion(e.target.value)}
        required
      />

      <input
        type="text"
        placeholder="Categoría"
        value={categoria}
        onChange={(e) => setCategoria(e.target.value)}
        required
      />

      <input
        type="number"
        placeholder="Precio"
        value={precio}
        onChange={(e) => setPrecio(e.target.value)}
        required
      />

      <button type="submit">
        {productToEdit ? "Actualizar" : "Guardar"}
      </button>

    </form>
  );
}

export default ProductForm;
